    { id: 719, word: "defend", phonetic: "/dɪˈfend/", hintSentence: "The soldiers fought bravely to defend their country against the invaders.", pos: "v.", meaning: "保卫，防守，辩护", usage: "defend oneself (自我防卫)", forms: "【名词】defense | 【形容词】defensive", cetSentences: "The lawyer had to defend a man who was clearly guilty." },
    { id: 720, word: "deficiency", phonetic: "/dɪˈfɪʃnsi/", hintSentence: "A deficiency of Vitamin D can lead to serious health issues.", pos: "n.", meaning: "缺乏，不足，缺点", usage: "vitamin deficiency (维生素缺乏)", forms: "【形容词】deficient", cetSentences: "The report highlighted several major deficiencies in the current safety system." }
